function updateCheckoutUI(){const c=checkoutCalc(); const set=(id,v)=>{const el=$('#'+id); if(el)el.textContent=typeof v==='number'?money(v):v}; set('coSubtotal',c.subtotal); set('coShipping',c.shipping); set('coHandling',c.handling); set('coDiscount',c.discount); set('coTotal',c.total); set('coPayable',c.total); const w=$('#coWeight'); if(w)w.textContent=(Math.round(c.weight*10)/10)+' kg'; const ss=$('#standardShipPreview'); if(ss)ss.textContent=money(estimateShipping(c.weight,c.subtotal,'standard')); const ps=$('#premiumShipPreview'); if(ps)ps.textContent=money(estimateShipping(c.weight,c.subtotal,'premium')); const msg=$('#couponMsg'); if(msg){const code=($('#couponCode')?.value||'').trim(); msg.textContent=code?(c.discount?'Coupon applied: '+money(c.discount)+' off':'Coupon not eligible for this order'):''}}
function animateStats(){$$('.live-stat').forEach(el=>{const target=Number(el.dataset.count)||0; let start=0,steps=24; const tick=()=>{start++; el.textContent=Math.round(target*start/steps).toLocaleString('en-IN'); if(start<steps)requestAnimationFrame(tick)}; tick()})}

