function badges(){let b=[['Verified Seller','Approved documents and admin review','verified'],['Trusted Dealer','Premium seller profile and strong activity','dealer'],['Top Rated','Excellent buyer ratings and deal history','rated'],['Fast Responder','Quick replies inside Harvester Parts chat','fast'],['100+ Listings','Large active catalog on the marketplace','power'],['Safe Seller','Low reports and verified transaction conduct','safe']]; return `<section class="section"><p class="eyebrow">Rewards</p><h2>Premium trust badges.</h2><p>Badges are designed to make buyers feel safe before they order or message a seller.</p></section><div class="badge-showcase pro-badges">${b.map((x,i)=>`<div class="custom-badge-card ${i?'locked':''}"><div class="custom-badge ${x[2]}"><span></span><b>${esc(x[0])}</b></div><h3>${esc(x[0])}</h3><p>${esc(i?x[1]:'Aadhaar/shop verification approved by admin.')}</p><strong>${i?'Locked':'Active'}</strong></div>`).join('')}</div>`}
